package com.eventstreaming.producer;

import com.eventstreaming.model.Event;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class EventProducer {

    private static final Logger logger = LoggerFactory.getLogger(EventProducer.class);

    private final KafkaTemplate<String, Event> kafkaTemplate;

    public EventProducer(KafkaTemplate<String, Event> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void sendEvent(String topic, Event event) {
        logger.info("Publishing event to topic '{}': {}", topic, event);

        CompletableFuture<SendResult<String, Event>> future =
                kafkaTemplate.send(topic, event.getEventId(), event);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Event sent successfully to topic '{}' partition [{}] offset [{}]",
                        topic,
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to send event to topic '{}': {}", topic, ex.getMessage(), ex);
            }
        });
    }

    public void sendEventWithKey(String topic, String key, Event event) {
        logger.info("Publishing event with key '{}' to topic '{}': {}", key, topic, event);

        CompletableFuture<SendResult<String, Event>> future =
                kafkaTemplate.send(topic, key, event);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Event with key '{}' sent successfully to topic '{}' partition [{}] offset [{}]",
                        key, topic,
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to send event with key '{}' to topic '{}': {}", key, topic, ex.getMessage(), ex);
            }
        });
    }
}

