package com.eventstreaming.consumer;

import com.eventstreaming.model.Event;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.handler.annotation.Header;
import org.springframework.messaging.handler.annotation.Payload;
import org.springframework.stereotype.Service;

@Service
public class UserEventConsumer {

    private static final Logger logger = LoggerFactory.getLogger(UserEventConsumer.class);

    @KafkaListener(
            topics = "user-events",
            groupId = "event-streaming-group",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeUserEvent(
            @Payload Event event,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
            @Header(KafkaHeaders.OFFSET) long offset) {

        logger.info("Received user event from topic '{}' partition [{}] offset [{}]: {}",
                topic, partition, offset, event);

        try {
            processUserEvent(event);
            logger.info("Successfully processed user event: {}", event.getEventId());
        } catch (Exception e) {
            logger.error("Error processing user event {}: {}", event.getEventId(), e.getMessage(), e);
            throw e;
        }
    }

    private void processUserEvent(Event event) {
        String eventType = event.getEventType();
        switch (eventType) {
            case "USER_CREATED":
                logger.info("Processing new user creation: {}", event.getPayload());
                break;
            case "USER_UPDATED":
                logger.info("Processing user update: {}", event.getPayload());
                break;
            case "USER_DELETED":
                logger.info("Processing user deletion: {}", event.getPayload());
                break;
            default:
                logger.warn("Unknown user event type: {}", eventType);
        }
    }
}

