package com.eventstreaming.controller;

import com.eventstreaming.model.Event;
import com.eventstreaming.producer.EventProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private static final Logger logger = LoggerFactory.getLogger(EventController.class);

    private final EventProducer eventProducer;

    public EventController(EventProducer eventProducer) {
        this.eventProducer = eventProducer;
    }

    @PostMapping("/user")
    public ResponseEntity<Map<String, String>> publishUserEvent(@RequestBody Event event) {
        logger.info("Received request to publish user event: {}", event);
        event.setSource("user-service");
        eventProducer.sendEvent("user-events", event);
        return buildResponse(event.getEventId(), "User event published successfully");
    }

    @PostMapping("/order")
    public ResponseEntity<Map<String, String>> publishOrderEvent(@RequestBody Event event) {
        logger.info("Received request to publish order event: {}", event);
        event.setSource("order-service");
        eventProducer.sendEvent("order-events", event);
        return buildResponse(event.getEventId(), "Order event published successfully");
    }

    @PostMapping("/notification")
    public ResponseEntity<Map<String, String>> publishNotificationEvent(@RequestBody Event event) {
        logger.info("Received request to publish notification event: {}", event);
        event.setSource("notification-service");
        eventProducer.sendEvent("notification-events", event);
        return buildResponse(event.getEventId(), "Notification event published successfully");
    }

    @PostMapping("/{topic}")
    public ResponseEntity<Map<String, String>> publishToTopic(
            @PathVariable String topic,
            @RequestBody Event event) {
        logger.info("Received request to publish event to topic '{}': {}", topic, event);
        eventProducer.sendEvent(topic, event);
        return buildResponse(event.getEventId(), "Event published to topic '" + topic + "' successfully");
    }

    @PostMapping("/{topic}/keyed")
    public ResponseEntity<Map<String, String>> publishKeyedEvent(
            @PathVariable String topic,
            @RequestParam String key,
            @RequestBody Event event) {
        logger.info("Received request to publish keyed event to topic '{}' with key '{}': {}", topic, key, event);
        eventProducer.sendEventWithKey(topic, key, event);
        return buildResponse(event.getEventId(), "Keyed event published to topic '" + topic + "' successfully");
    }

    private ResponseEntity<Map<String, String>> buildResponse(String eventId, String message) {
        Map<String, String> response = new HashMap<>();
        response.put("eventId", eventId);
        response.put("status", "ACCEPTED");
        response.put("message", message);
        return new ResponseEntity<>(response, HttpStatus.ACCEPTED);
    }
}

